    92→  var RAIOX_KEY = 'jakeos_raiox_2026';
    93→
    94→  function salvarRaioX() {
    95→    try {
    96→      localStorage.setItem(RAIOX_KEY, JSON.stringify(RAIOX));
    97→      flashRaioX('✓ Salvo');
    98→    } catch(e) {}
    99→  }
   100→
   101→  function carregarRaioX() {
   102→    try {
   103→      var salvo = localStorage.getItem(RAIOX_KEY);
   104→      if (salvo) return JSON.parse(salvo);
   105→    } catch(e) {}
   106→    return null;
   107→  }
   108→
   109→  function flashRaioX(msg) {
   110→    var el = document.getElementById('fin-raiox-status');
   111→    if (!el) return;
   112→    el.textContent = msg;
   113→    el.classList.add('fin-raiox-status-visible');
   114→    clearTimeout(el._timer);
   115→    el._timer = setTimeout(function() { el.classList.remove('fin-raiox-status-visible'); }, 2000);
   116→  }
   117→
   118→  var RAIOX = carregarRaioX() || JSON.parse(JSON.stringify(RAIOX_PADRAO));
   119→
   120→  var MESES_LABEL = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];
   121→
   122→  // ── ESTADO ─────────────────────────────────────────────────────────────────
   123→  var mesSelecionado = new Date().getMonth() + 1;
   124→  var anoSelecionado = new Date().getFullYear();
   125→  var chartBarras    = null;
   126→  var chartDonut     = null;
   127→  var chartLinha     = null;
   128→  var chartMilhao    = null;
   129→  var metaMilhao     = 1000000;
   130→
   131→  // ── UTILITÁRIOS ────────────────────────────────────────────────────────────
   132→  function fmt(v) {
   133→    return 'R$ ' + Math.abs(v).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
   134→  }
   135→  function fmtK(v) {
   136→    if (Math.abs(v) >= 1000000) return 'R$ ' + (v/1000000).toFixed(2).replace('.',',') + 'M';
   137→    if (Math.abs(v) >= 1000)    return 'R$ ' + (v/1000).toFixed(1).replace('.',',') + 'K';
   138→    return fmt(v);
   139→  }
   140→  function mesLabel(mes, ano) {
   141→    var n = ['','Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];
   142→    return n[mes] + ' ' + ano;
   143→  }
   144→  function transacoesDo(mes, ano) {
   145→    var y = String(ano), m = String(mes).padStart(2,'0');
   146→    return TRANSACOES.filter(function(t){ return t.data.startsWith(y+'-'+m); });
   147→  }
   148→  function calcularKPIs(mes, ano) {
   149→    var lista    = transacoesDo(mes, ano);
   150→    var receita  = lista.filter(function(t){ return t.tipo==='Entrada'; }).reduce(function(s,t){ return s+t.valor; },0);
   151→    var despesas = lista.filter(function(t){ return t.tipo==='Saída';   }).reduce(function(s,t){ return s+t.valor; },0);
   152→    return { receita:receita, despesas:despesas, saldo:receita-despesas };
   153→  }
   154→
   155→  // ── RAIO-X: somatórios ─────────────────────────────────────────────────────
   156→  function raixoSomaLinha(itens, mes) {
   157→    return itens.reduce(function(s,item){ return s + (item.v[mes] || 0); }, 0);
   158→  }
   159→  function raixoTotaisMensais() {
   160→    var totais = { receitas:[], fixas:[], variaveis:[], saldo:[], acumulado:[] };
   161→    var acum = 0;
   162→    for (var m = 0; m < 12; m++) {
   163→      var r = raixoSomaLinha(RAIOX.entradas, m);
   164→      var f = raixoSomaLinha(RAIOX.fixas, m);
   165→      var v = raixoSomaLinha(RAIOX.variaveis, m);
   166→      var s = r - f - v;
   167→      acum += s;
   168→      totais.receitas.push(r);
   169→      totais.fixas.push(f);
   170→      totais.variaveis.push(v);
   171→      totais.saldo.push(s);
   172→      totais.acumulado.push(acum);
   173→    }
   174→    return totais;
   175→  }
   176→
   177→  // ── INICIALIZAÇÃO ──────────────────────────────────────────────────────────
   178→  function initFinanceiro() {
   179→    // Tabs internos
   180→    document.querySelectorAll('.fin-tab-btn').forEach(function(btn) {
   181→      btn.addEventListener('click', function() {
   182→        var tab = this.dataset.tab;
   183→        document.querySelectorAll('.fin-tab-btn').forEach(function(b){ b.classList.remove('active'); });
   184→        document.querySelectorAll('.fin-tab-pane').forEach(function(p){ p.classList.remove('active'); });
   185→        this.classList.add('active');
   186→        var pane = document.getElementById('fin-pane-' + tab);
   187→        if (pane) pane.classList.add('active');
   188→        if (tab === 'visao-geral')  { renderCharts(); renderRaioX(); }
   189→        if (tab === 'projecoes')    { renderGraficoLinha(); atualizarProjecoes(); }
   190→        if (tab === 'milhao')       { initProjetoMilhao(); }
   191→      });
   192→    });
   193→
   194→    // IA
   195→    var btnIA = document.getElementById('fin-ai-btn');
   196→    if (btnIA) btnIA.addEventListener('click', gerarAnaliseIA);
   197→
   198→    // Filtro de mês na Visão Geral
   199→    var selectMes = document.getElementById('fin-visao-mes');
   200→    if (selectMes) {
   201→      selectMes.value = String(mesSelecionado);
   202→      selectMes.addEventListener('change', function () {
   203→        var novoMes = parseInt(this.value, 10) || mesSelecionado;
   204→        mesSelecionado = novoMes;
   205→        anoSelecionado = 2026;
   206→        atualizarTudo();
   207→        renderRaioX();
   208→      });
   209→    }
   210→
   211→    atualizarTudo();
   212→    renderRaioX();
   213→  }
   214→
   215→  function atualizarTudo() {
   216→    atualizarKPIs();
   217→    atualizarProjecoes();
   218→    renderCharts();
   219→  }
   220→
   221→  // ── KPIs — usa RAIOX como fonte principal ──────────────────────────────────
   222→  function calcularKPIsFromRaioX(mes, ano) {
   223→    if (ano !== 2026) return calcularKPIs(mes, ano);
   224→    var idx      = mes - 1;
   225→    var receita  = raixoSomaLinha(RAIOX.entradas,   idx);
   226→    var fixas    = raixoSomaLinha(RAIOX.fixas,       idx);
   227→    var variaveis = raixoSomaLinha(RAIOX.variaveis,  idx);
   228→    return { receita: receita, despesas: fixas + variaveis, saldo: receita - fixas - variaveis };
   229→  }
   230→
   231→  function atualizarKPIs() {
   232→    var kpis = calcularKPIsFromRaioX(mesSelecionado, anoSelecionado);
   233→    var acumulado = 0;
   234→    for (var m = 1; m <= mesSelecionado; m++) {
   235→      acumulado += calcularKPIsFromRaioX(m, anoSelecionado).saldo;
   236→    }
   237→    var elR = document.getElementById('fin-kpi-receita');
   238→    var elD = document.getElementById('fin-kpi-despesas');
   239→    var elS = document.getElementById('fin-kpi-saldo');
   240→    var elP = document.getElementById('fin-kpi-projecao');
   241→    var elM = document.getElementById('fin-kpi-receita-mes');
   242→    if (elR) elR.textContent = fmt(kpis.receita);
   243→    if (elD) elD.textContent = fmt(kpis.despesas);
   244→    if (elM) elM.textContent = mesLabel(mesSelecionado, anoSelecionado);
   245→    if (elS) {
   246→      elS.textContent = (kpis.saldo < 0 ? '-' : '') + fmt(kpis.saldo);
   247→      elS.className = 'fin-kpi-value ' + (kpis.saldo >= 0 ? 'fin-val-positive' : 'fin-val-negative');
   248→    }
   249→    if (elP) {
   250→      elP.textContent = (acumulado < 0 ? '-' : '') + fmt(acumulado);
   251→      elP.className = 'fin-kpi-value ' + (acumulado >= 0 ? 'fin-val-positive' : 'fin-val-negative');
   252→    }
   253→  }
   254→
   255→  // ── RAIO-X TABLE ───────────────────────────────────────────────────────────
   256→  function renderRaioX() {
   257→    var table = document.getElementById('fin-raiox-table');
   258→    if (!table) return;
   259→
   260→    var totais = raixoTotaisMensais();
   261→    var html = '';
   262→
   263→    // Cabeçalho
   264→    html += '<thead><tr><th class="fin-rx-th-label">Item</th>';
   265→    MESES_LABEL.forEach(function(m, i) {
   266→      var isPast = (i + 1) < mesSelecionado || (i + 1 === mesSelecionado);
   267→      html += '<th class="fin-rx-th-mes' + (isPast ? ' fin-rx-past' : ' fin-rx-future') + '">' + m + '</th>';
   268→    });
   269→    html += '<th class="fin-rx-th-anual">Total 2026</th></tr></thead>';
   270→
   271→    html += '<tbody>';
   272→
   273→    // ── ENTRADAS
   274→    html += '<tr class="fin-rx-section-header"><td colspan="14">↑ RECEITAS</td></tr>';
   275→    RAIOX.entradas.forEach(function(item, idx) {
   276→      html += renderRaioXLinha(item, 'entrada', 'entradas', idx);
   277→    });
   278→    html += renderRaioXAddLinha('entradas', 'entrada');
   279→    html += renderRaioXTotalLinha('TOTAL RECEITAS', totais.receitas, 'fin-rx-total fin-rx-total-entrada');
   280→
   281→    // ── DESPESAS FIXAS
   282→    html += '<tr class="fin-rx-section-header fin-rx-sec-saida"><td colspan="14">↓ DESPESAS FIXAS</td></tr>';
   283→    RAIOX.fixas.forEach(function(item, idx) {
   284→      html += renderRaioXLinha(item, 'fixa', 'fixas', idx);
   285→    });
   286→    html += renderRaioXAddLinha('fixas', 'fixa');
   287→    html += renderRaioXTotalLinha('TOTAL FIXAS', totais.fixas, 'fin-rx-total fin-rx-total-saida');
   288→
   289→    // ── DESPESAS VARIÁVEIS
   290→    html += '<tr class="fin-rx-section-header fin-rx-sec-var"><td colspan="14">↓ DESPESAS VARIÁVEIS</td></tr>';
   291→    RAIOX.variaveis.forEach(function(item, idx) {
   292→      html += renderRaioXLinha(item, 'variavel', 'variaveis', idx);
   293→    });
   294→    html += renderRaioXAddLinha('variaveis', 'variavel');
   295→    html += renderRaioXTotalLinha('TOTAL VARIÁVEIS', totais.variaveis, 'fin-rx-total fin-rx-total-saida');
   296→
   297→    // ── RESUMO
   298→    html += '<tr class="fin-rx-section-header fin-rx-sec-resumo"><td colspan="14">◈ RESUMO</td></tr>';
   299→    html += renderRaioXSaldoLinha('SALDO MENSAL', totais.saldo);
   300→    html += renderRaioXAcumLinha('ACUMULADO', totais.acumulado);
