   722→    if (btnCalc) btnCalc.addEventListener('click', calcularMilhao);
   723→
   724→    // Recalcular em tempo real ao mudar inputs
   725→    ['mil-aporte','mil-patrimonio','mil-taxa'].forEach(function(id) {
