   733→
   734→  function calcularMilhao() {
   735→    var aporte     = parseFloat(document.getElementById('mil-aporte')    ?.value) || 0;
   736→    var patrimonio = parseFloat(document.getElementById('mil-patrimonio') ?.value) || 0;
   737→    var taxa       = (parseFloat(document.getElementById('mil-taxa')      ?.value) || 1) / 100;
   738→    var meta       = metaMilhao;
   739→
   740→    // Data de nascimento: 05/04/2001
   741→    var nascimento = new Date(2001, 3, 5); // April 5, 2001
   742→
   743→    if (aporte <= 0 && patrimonio < meta) {
   744→      return;
   745→    }
   746→
   747→    // Cálculo iterativo: FV = PV*(1+r)^n + PMT*((1+r)^n - 1)/r
   748→    var n = 0, fv = patrimonio;
   749→    var MAX = 12000; // 1000 anos max
   750→    while (fv < meta && n < MAX) {
   751→      fv = fv * (1 + taxa) + aporte;
   752→      n++;
   753→    }
   754→
   755→    if (n >= MAX) {
   756→      // Nunca vai atingir
   757→      var elData  = document.getElementById('mil-data');
   758→      var elIdade = document.getElementById('mil-idade');
   759→      if (elData)  elData.textContent  = 'Nunca com este aporte';
   760→      if (elIdade) elIdade.textContent = 'Aumente o aporte mensal';
   761→      return;
   762→    }
   763→
   764→    // Data alvo
   765→    var hoje       = new Date();
   766→    var dataAlvo   = new Date(hoje);
   767→    dataAlvo.setMonth(dataAlvo.getMonth() + n);
   768→
   769→    // Idade na data alvo
   770→    var diffMs    = dataAlvo - nascimento;
   771→    var idadeTotal = diffMs / (1000 * 60 * 60 * 24 * 365.25);
   772→    var anos      = Math.floor(idadeTotal);
   773→    var mesesR    = Math.floor((idadeTotal - anos) * 12);
   774→
   775→    // Total aportado vs juros
   776→    var totalAportado = aporte * n + patrimonio;
   777→    var jurosGerados  = fv - totalAportado;
   778→
   779→    // Progresso atual
   780→    var pct = Math.min((patrimonio / meta) * 100, 100);
   781→
   782→    // Mostrar display
   783→    var idle    = document.getElementById('mil-idle');
   784→    var display = document.getElementById('mil-display');
   785→    if (idle)    idle.classList.add('hidden');
   786→    if (display) display.classList.remove('hidden');
   787→
   788→    // Preencher valores
   789→    var elData  = document.getElementById('mil-data');
   790→    var elIdade = document.getElementById('mil-idade');
   791→    var elMeses = document.getElementById('mil-meses');
   792→    var elTotalA= document.getElementById('mil-total-aportado');
   793→    var elJuros = document.getElementById('mil-juros');
   794→    var elFill  = document.getElementById('mil-prog-fill');
   795→    var elGlow  = document.getElementById('mil-prog-glow');
   796→    var elPct   = document.getElementById('mil-prog-pct');
   797→    var elAtual = document.getElementById('mil-prog-atual');
   798→    var elMeta  = document.getElementById('mil-prog-meta');
   799→    var badge   = document.getElementById('mil-meta-badge');
   800→
   801→    var meses_str = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];
   802→    var dataStr = ('0' + dataAlvo.getDate()).slice(-2) + '/' + meses_str[dataAlvo.getMonth()] + '/' + dataAlvo.getFullYear();
   803→
   804→    if (badge)   badge.textContent = 'Meta: ' + fmt(meta);
   805→    if (elData)  elData.textContent  = dataStr;
   806→    if (elIdade) elIdade.textContent = anos + ' anos e ' + mesesR + ' meses';
   807→    if (elMeses) elMeses.textContent = n + ' meses (' + Math.floor(n/12) + ' anos)';
   808→    if (elTotalA) elTotalA.textContent = fmt(totalAportado);
   809→    if (elJuros)  elJuros.textContent  = fmt(jurosGerados);
   810→    if (elFill)   elFill.style.width   = pct + '%';
   811→    if (elGlow)   elGlow.style.left    = pct + '%';
   812→    if (elPct)    elPct.textContent    = pct.toFixed(1) + '% concluído';
   813→    if (elAtual)  elAtual.textContent  = fmt(patrimonio);
   814→    if (elMeta)   elMeta.textContent   = fmt(meta);
   815→
   816→    // Mini gráfico de evolução
   817→    renderMilhaoChart(n, aporte, patrimonio, taxa, meta);
   818→  }
   819→
   820→  function renderMilhaoChart(n, aporte, patrimonio, taxa, meta) {
   821→    var canvas = document.getElementById('mil-chart-evolucao');
   822→    if (!canvas || typeof Chart === 'undefined') return;
   823→
   824→    var nascimento = new Date(2001, 3, 5);
   825→    var hoje = new Date();
   826→
   827→    // Gerar pontos a cada step meses
   828→    var pontos = [], labels = [], idadesAnos = [], idadesMeses = [];
   829→    var fv = patrimonio;
   830→    var step = Math.max(1, Math.floor(n / 40)); // max 40 pontos
   831→    for (var i = 0; i <= n; i++) {
   832→      if (i % step === 0 || i === n) {
   833→        var dataPoint = new Date(hoje);
   834→        dataPoint.setMonth(dataPoint.getMonth() + i);
   835→        var diffMs = dataPoint - nascimento;
   836→        var idadeF = diffMs / (1000 * 60 * 60 * 24 * 365.25);
   837→        var anos   = Math.floor(idadeF);
   838→        var meses  = Math.floor((idadeF - anos) * 12);
   839→        labels.push(anos + ' anos');
   840→        idadesAnos.push(anos);
   841→        idadesMeses.push(meses);
   842→        pontos.push(parseFloat(fv.toFixed(2)));
   843→      }
   844→      fv = fv * (1 + taxa) + aporte;
   845→    }
   846→
   847→    if (chartMilhao) chartMilhao.destroy();
   848→    chartMilhao = new Chart(canvas, {
