   850→      data: {
   851→        labels: labels,
   852→        datasets: [{
   853→          label: 'Patrimônio',
   854→          data: pontos,
   855→          borderColor: '#00e5ff',
   856→          backgroundColor: 'rgba(0,229,255,0.08)',
   857→          borderWidth: 2,
   858→          pointRadius: 0,
   859→          pointHoverRadius: 5,
   860→          pointHoverBackgroundColor: '#00e5ff',
   861→          tension: 0.4,
   862→          fill: true,
   863→        },{
   864→          label: 'Meta',
