   866→          borderColor: 'rgba(105,240,174,0.5)',
   867→          borderWidth: 1,
   868→          borderDash: [6,4],
   869→          pointRadius: 0,
   870→          fill: false,
   871→        }]
   872→      },
   873→      options: {
   874→        responsive: true, maintainAspectRatio: false,
   875→        interaction: { mode: 'index', intersect: false },
   876→        plugins: {
   877→          legend: { labels: { color: '#b0bec5', font: { family: 'Rajdhani', size: 11 }, boxWidth: 12 } },
   878→          tooltip: {
   879→            callbacks: {
   880→              title: function(items) {
   881→                var idx = items[0].dataIndex;
   882→                return idadesAnos[idx] + ' anos e ' + idadesMeses[idx] + ' meses';
   883→              },
   884→              label: function(ctx) {
   885→                if (ctx.datasetIndex === 0) {
   886→                  return ' Patrimônio: R$ ' + ctx.raw.toLocaleString('pt-BR', {minimumFractionDigits:2});
   887→                }
   888→                return ' Meta: R$ ' + ctx.raw.toLocaleString('pt-BR', {minimumFractionDigits:2});
   889→              }
   890→            }
   891→          }
   892→        },
   893→        scales: {
   894→          x: {
   895→            ticks: { color: '#b0bec5', font: { family: 'Rajdhani', size: 10 }, maxTicksLimit: 10 },
   896→            grid: { color: 'rgba(0,229,255,0.06)' },
   897→            title: { display: true, text: 'Idade', color: '#546e7a', font: { family: 'Rajdhani', size: 12 } }
   898→          },
   899→          y: {
   900→            ticks: { color: '#b0bec5', font: { family: 'Rajdhani', size: 11 }, callback: function(v){ return 'R$ '+(v/1000).toFixed(0)+'K'; } },
   901→            grid: { color: 'rgba(0,229,255,0.06)' },
