   920→    var kpisAnt = mesSelecionado > 1 ? calcularKPIs(mesSelecionado-1, anoSelecionado) : {receita:0,despesas:0,saldo:0};
   921→    var payload = { mes: mesLabel(mesSelecionado, anoSelecionado), receita: kpis.receita, despesas: kpis.despesas, saldo: kpis.saldo, receita_ant: kpisAnt.receita, desp_ant: kpisAnt.despesas };
   922→
   923→    fetch('/api/financeiro/analise', { method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify(payload) })
   924→    .then(function(r){ return r.json(); })
   925→    .then(function(data) {
   926→      loading.classList.add('hidden');
   927→      text.classList.remove('hidden');
   928→      text.innerHTML = '<span class="fin-ai-jake">🤖 Jake diz:</span><br>' + (data.analise || 'Análise indisponível.');
   929→    })
   930→    .catch(function() {
   931→      loading.classList.add('hidden');
   932→      text.classList.remove('hidden');
   933→      var difR = kpis.receita - kpisAnt.receita, difD = kpis.despesas - kpisAnt.despesas;
   934→      text.innerHTML = '<span class="fin-ai-jake">🤖 Jake diz:</span><br>' + gerarAnaliseLocal(kpis, kpisAnt, difR, difD);
   935→    });
   936→  }
