   938→  function gerarAnaliseLocal(kpis, kpisAnt, difR, difD) {
   939→    var partes = [];
   940→    if (kpisAnt.receita > 0) {
   941→      var varR = ((difR / kpisAnt.receita) * 100).toFixed(1);
   942→      partes.push(difR > 0
   943→        ? 'Suas receitas cresceram <strong>' + varR + '%</strong> em relação ao mês anterior — ótima evolução!'
   944→        : difR < 0 ? 'Suas receitas recuaram <strong>' + Math.abs(varR) + '%</strong> vs. mês anterior. Reveja a entrada de novos projetos.'
   945→        : 'Suas receitas se mantiveram estáveis.');
   946→    }
   947→    var tx = ((kpis.despesas / kpis.receita) * 100).toFixed(1);
   948→    partes.push('Você comprometeu <strong>' + tx + '%</strong> da receita com despesas este mês.');
   949→    partes.push(kpis.saldo >= 0
   950→      ? 'Saldo positivo de <strong>' + fmt(kpis.saldo) + '</strong> — considere destinar parte para investimentos e reserva de emergência.'
   951→      : 'Saldo negativo de <strong>' + fmt(Math.abs(kpis.saldo)) + '</strong> — revise despesas variáveis e parcelamentos.');
   952→    return partes.join(' ');
   953→  }
