  var _syncListenersAtivos = false;
  function sincronizarScrollTopo() {
    // Double RAF: garante que o browser terminou de calcular o layout
    requestAnimationFrame(function() {
      requestAnimationFrame(function() {
        var sBot  = document.getElementById('fin-raiox-scroll');
        var sTop  = document.getElementById('fin-raiox-scroll-top');
        var inner = document.getElementById('fin-raiox-scroll-top-inner');
        var table = document.getElementById('fin-raiox-table');
        if (!sBot || !sTop || !inner) return;

        var largura = table ? table.offsetWidth : sBot.scrollWidth;
        inner.style.width = largura + 'px';

        if (!_syncListenersAtivos) {
          _syncListenersAtivos = true;
          sTop.addEventListener('scroll', function() { sBot.scrollLeft = sTop.scrollLeft; });
          sBot.addEventListener('scroll', function() { sTop.scrollLeft = sBot.scrollLeft; });
        }
      });
    });
  }

