}

.sa-upload-card {
  display: flex;
  flex-direction: column;
  gap: .35rem;
}

.sa-dropzone {
  border: 1px dashed rgba(0,229,255,.2);
  border-radius: 10px;
  padding: .6rem;
  min-height: 80px;
