  overflow: hidden;
  transition: border-color .2s, background .2s;
}

.sa-dropzone:hover,
.sa-dropzone.sa-dragover {
  border-color: var(--cyan);
  background: rgba(0,229,255,.05);
}

.sa-file-input {
  position: absolute;
  inset: 0;
  opacity: 0;
  cursor: pointer;
}

.sa-drop-placeholder {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: .3rem;
  color: rgba(176,190,197,.5);
  font-size: .8rem;
  pointer-events: none;
}

.sa-drop-placeholder span {
  font-size: 1.2rem;
}

.sa-preview {
  width: 100%;
  border-radius: 8px;
  object-fit: cover;
}

.sa-preview-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0,1fr));
  gap: .3rem;
  width: 100%;
}

.sa-preview-grid img {
  width: 100%;
