  1671→
  1672→  // ── Carregar clientes do servidor ──────────────────
  1673→  function carregarClientes() {
  1674→    fetch('/api/anuncios/clientes')
  1675→      .then(function(r){ return r.json(); })
  1676→      .then(function(data) {
  1677→        _clientes = data.clientes || [];
  1678→        renderSidebar();
  1679→      })
  1680→      .catch(function(e) { console.error('Erro ao carregar clientes:', e); });
  1681→  }
  1682→
  1683→  function renderSidebar() {
  1684→    var grupos = { piloti: [], dentto: [], freelance: [] };
  1685→    _clientes.forEach(function(c) {
  1686→      if (grupos[c.agencia]) grupos[c.agencia].push(c);
  1687→    });
  1688→    ['piloti','dentto','freelance'].forEach(function(ag) {
  1689→      var ul = document.getElementById('anu-lista-' + ag);
  1690→      if (!ul) return;
  1691→      ul.innerHTML = grupos[ag].map(function(c) {
  1692→        var ativo = _clienteAtivo && _clienteAtivo.id === c.id ? ' active' : '';
  1693→        return '<li class="anu-cliente-item' + ativo + '" data-id="' + c.id + '">' +
  1694→          '<span class="anu-cliente-item-nome">' + _esc(c.nome) + '</span>' +
  1695→          '<button class="anu-cliente-edit-btn" data-id="' + c.id + '" title="Editar">✎</button>' +
  1696→          '</li>';
  1697→      }).join('');
  1698→      // Bind clicks
  1699→      ul.querySelectorAll('.anu-cliente-item').forEach(function(li) {
  1700→        li.addEventListener('click', function(e) {
  1701→          if (e.target.classList.contains('anu-cliente-edit-btn')) return;
  1702→          var id = parseInt(this.dataset.id);
  1703→          selecionarCliente(id);
  1704→        });
  1705→      });
  1706→      ul.querySelectorAll('.anu-cliente-edit-btn').forEach(function(btn) {
