  1769→    _set('anu-pf-whatsapp',   c.whatsapp || '');
  1770→    _set('anu-pf-camp-tipo',  c.campanha_tipo || 'MESSAGES');
  1771→    _set('anu-pf-orcamento',  c.orcamento_diario || '');
  1772→    var loc = c.localizacao_json;
  1773→    document.getElementById('anu-pf-localizacao').value =
  1774→      loc ? JSON.stringify(loc, null, 2) : '';
  1775→    var pub = c.publico_json;
