  1790→  }
  1791→
  1792→  function salvarPerfil() {
  1793→    var nome       = _val('anu-pf-nome').trim();
  1794→    var agencia    = _val('anu-pf-agencia');
  1795→    var account_id = _val('anu-pf-account-id').trim();
  1796→    var token_key  = _val('anu-pf-token-key');
  1797→    var locStr     = _val('anu-pf-localizacao').trim();
  1798→
  1799→    if (!nome || !account_id || !locStr) {
  1800→      alert('Nome, Account ID e Localização são obrigatórios.');
  1801→      return;
  1802→    }
  1803→
  1804→    var localizacao_json, publico_json;
  1805→    try { localizacao_json = JSON.parse(locStr); }
  1806→    catch(e) { alert('Localização inválida — verifique o JSON.'); return; }
  1807→
  1808→    var pubStr = _val('anu-pf-publico').trim();
