  1810→    catch(e) { alert('Público inválido — verifique o JSON.'); return; }
  1811→
  1812→    var payload = {
  1813→      nome: nome, agencia: agencia, account_id: account_id,
  1814→      token_key: token_key, whatsapp: _val('anu-pf-whatsapp'),
  1815→      campanha_tipo: _val('anu-pf-camp-tipo'),
