  1817→      localizacao_json: localizacao_json, publico_json: publico_json
  1818→    };
  1819→
  1820→    var url    = _modoPerfilId ? '/api/anuncios/clientes/' + _modoPerfilId : '/api/anuncios/clientes';
  1821→    var method = _modoPerfilId ? 'PUT' : 'POST';
  1822→
  1823→    fetch(url, { method: method, headers: {'Content-Type':'application/json'}, body: JSON.stringify(payload) })
  1824→      .then(function(r){ return r.json(); })
  1825→      .then(function(data) {
  1826→        if (data.error) { alert('Erro: ' + data.error); return; }
  1827→        carregarClientes();
  1828→        esconder('anu-perfil-form');
  1829→        if (_modoPerfilId) {
  1830→          // Recarregar cliente ativo se foi editado
  1831→          fetch('/api/anuncios/clientes')
  1832→            .then(function(r){ return r.json(); })
